.whatsapp-modal {
  z-index: 100;
  pointer-events: none;
  flex-flow: column;
  justify-content: center;
  align-items: center;
  display: flex;
  position: fixed;
  inset: 0;
}

.whatsapp-modal__card {
  transition: all 0.6s cubic-bezier(0.625, 0.05, 0, 1);
  grid-column-gap: 1.25em;
  grid-row-gap: 1.25em;
  pointer-events: auto;
  background-color: #f8f6f3;
  border-radius: 1.5em;
  flex-flow: column;
  align-items: center;
  width: 20em;
  padding: 4.5em 2em 3.26em;
  display: flex;
  position: relative;
  transform: translateY(25%) rotate(0.001deg);
  opacity: 0;
  visibility: hidden;
}

[data-whatsapp-modal-status="active"] .whatsapp-modal__card {
  transform: translateY(0%) rotate(0.001deg);
  opacity: 1;
  visibility: visible;
}

.whatsapp-modal__qr-canvas {
  background-color: #0000001a;
  width: 8.75em;
  height: 8.75em;
}

[data-whatsapp-modal-qr-canvas]:has(svg) {
  background-color: transparent;
}

[data-whatsapp-modal-qr-canvas] svg rect {
  fill: transparent;
}

.whatsapp-modal__text {
  grid-column-gap: .75em;
  grid-row-gap: .75em;
  flex-flow: column;
  align-items: center;
  padding-top: 1em;
  display: flex;
}

.whatsapp-modal__h2 {
  text-align: center;
