  font-size: 1.75em;
  font-weight: 500;
  line-height: 1;
}

.whatsapp-modal__p {
  color: #0009;
  text-align: center;
  font-size: 1em;
}

.whatsapp-modal__btn {
  grid-column-gap: .5em;
  grid-row-gap: .5em;
  color: #fff;
  cursor: pointer;
  background-color: #612c08;
  border-radius: 30em;
  padding: 1em 1.5em;
  text-decoration: none;
  display: flex;
  position: relative;
  overflow: hidden;
}

.whatsapp-modal__btn-span {
  color: #f8f6f3;
