  font-weight: 500;
  line-height: 1;
}

.whatsapp-modal__overlay-link, 
.whatsapp-modal__overlay-toggle {
  width: 100%;
  height: 100%;
  position: absolute;
  top: 0;
  left: 0;
}

.whatsapp-modal__close {
  cursor: pointer;
