[data-whatsapp-modal-btn] [data-whatsapp-modal-link] {
  display: none;
}

/* Hide modal on touch devices, and open link directly */
@media (hover: none) and (pointer: coarse) {
  [data-whatsapp-modal] {
    display: none;
  }

  /* Hide toggle button on touch devices */
  [data-whatsapp-modal-trigger] [data-whatsapp-modal-toggle] {
    display: none;
  }

  /* Show link on touch devices */
  [data-whatsapp-modal-trigger] [data-whatsapp-modal-link] {
    display: block;
  }
}

Step 2: Add custom Javascript

function initWhatsAppModal() {

  const modal = document.querySelector('[data-whatsapp-modal]');

  // QR-code generation
  const url = (modal.getAttribute('data-whatsapp-modal') || '').trim();
  if (!url) return;

  // Generate an SVG QR via kjua
  const svg = kjua({
    text: url,
    render: 'svg',
    crisp: true,
    minVersion: 1,
    ecLevel: 'M',
    size: 540,
    fill: '#000000',
    back: '#FFFFFF',
    rounded: 0
  });

  // Let CSS control sizing
  svg.removeAttribute('width');
  svg.removeAttribute('height');
  svg.removeAttribute('style');

  // Insert into canvas (or multiple if needed)
  modal.querySelectorAll('[data-whatsapp-modal-qr-canvas]').forEach((placeholder, i) => {
    const node = i === 0 ? svg : svg.cloneNode(true);
    placeholder.appendChild(node);
  });

  // Add the link to all elements with [data-whatsapp-modal-link] attribute
  document.querySelectorAll('[data-whatsapp-modal-link]').forEach(linkEl => {
    linkEl.setAttribute('href', url);
    linkEl.setAttribute('target', '_blank');
  });

  // Toggle open/close the modal
  document.querySelectorAll('[data-whatsapp-modal-toggle]').forEach(btn => {
    btn.addEventListener('click', () => {
      if (!modal) return;
      const isActive = modal.getAttribute('data-whatsapp-modal-status') === 'active';
      modal.setAttribute('data-whatsapp-modal-status', isActive ? 'not-active' : 'active');
    });
  });

  // Close on ESC key
  document.addEventListener('keydown', event => {
    if (event.key === 'Escape' || event.keyCode === 27) {
      if (modal) {
        modal.setAttribute('data-whatsapp-modal-status', 'not-active');
      }
    }
  });
}

// Initialize WhatsApp Modal (Generate QR Code)
document.addEventListener('DOMContentLoaded', function() {
  initWhatsAppModal();
});

Implementation

Modal Container
Place the [data-whatsapp-modal] attribute on your modal wrapper. Its value should be the WhatsApp URL (e.g. https://wa.me/…). This url will be turned into a QR Code.
<div data-whatsapp-modal="https://wa.me/31612345678" class="whatsapp-modal">
  …  
div>
QR-Code Canvas
Inside your modal, add one or more placeholders with the [data-whatsapp-modal-qr-canvas] attribute. The script uses kjua to render an SVG QR code into each.

Link Elements
Any element with [data-whatsapp-modal-link] attribute will get its href set to your WhatsApp URL, plus target="_blank" (defined in the [data-whatsapp-modal] attribute).

Toggle Buttons
Add [data-whatsapp-modal-toggle] to one or more buttons to open/close the modal. Clicking toggles the attribute [data-whatsapp-modal-status] between active and not-active. We use CSS to animate the modal based on these values. With the Escape key on the keyboard it's also possible to close the modal.

Opening the modal (& touch devices)
To enable direct WhatsApp opening on touch devices (bypassing the modal), include both a [data-whatsapp-modal-link] and a [data-whatsapp-modal-toggle] attribute inside your external button, then add [data-whatsapp-modal-trigger] attribute to that button so the script knows which child element (the link or the toggle) to hide on touch- vs. non-touch devices. Example below:
<div data-whatsapp-modal-trigger="" class="whatsapp-modal__btn">
  <span class="whatsapp-modal__btn-span">WhatsApp usspan>


  <a data-whatsapp-modal-link="" href="#" class="whatsapp-modal__overlay-link">a>


  <div data-whatsapp-modal-toggle="" class="whatsapp-modal__overlay-toggle">div>
div>
